import os
import requests
import joblib

class ModelLoader:
    def __init__(self):
        self.model_path = os.getenv('MODEL_PATH')
        self.model = None
        self.load_model()

    def load_model(self):
        if not self.model_path:
            raise ValueError("MODEL_PATH environment variable is not set.")
        
        # Fetch the latest model from cloud storage
